text:
Looking at this, I'll build a single self-contained file with a procedural 2.5D metallic coin renderer on 2D canvas (deterministic `setTime`), plus four procedurally-rendered edition coins.

```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>WastedToken Mint — Collectible Physical Challenge Coins</title>
<style>
  :root{
    --bg:#0b0c10; --bg2:#141722; --ink:#efe9dc; --muted:#9aa0b0;
    --gold:#d9b34a; --gold2:#fff4c2; --line:rgba(255,255,255,.09);
    --card:#15171f;
  }
  *{box-sizing:border-box}
  html,body{margin:0;padding:0}
  body{
    background:
      radial-gradient(1200px 700px at 50% -10%, #1b2030 0%, rgba(27,32,48,0) 60%),
      linear-gradient(180deg,#0b0c10 0%, #0a0b0f 100%);
    color:var(--ink);
    font-family:"Segoe UI",Helvetica,Arial,sans-serif;
    -webkit-font-smoothing:antialiased;
    overflow-x:hidden;
  }
  .wrap{max-width:1180px;margin:0 auto;padding:0 24px}
  h1,h2,h3,.serif{font-family:Georgia,"Times New Roman",serif}
  a{color:inherit}

  /* NAV */
  header.nav{
    position:sticky;top:0;z-index:50;
    backdrop-filter:blur(10px);
    background:linear-gradient(180deg,rgba(11,12,16,.85),rgba(11,12,16,.35));
    border-bottom:1px solid var(--line);
  }
  .nav .wrap{display:flex;align-items:center;justify-content:space-between;height:66px}
  .brand{display:flex;align-items:center;gap:12px;font-weight:700;letter-spacing:.5px}
  .brand .mark{
    width:30px;height:30px;border-radius:50%;
    background:radial-gradient(circle at 35% 30%,var(--gold2),var(--gold) 45%,#6e4e12 100%);
    box-shadow:0 0 0 1px rgba(0,0,0,.5) inset, 0 2px 8px rgba(0,0,0,.5);
  }
  .brand b{font-family:Georgia,serif;font-size:18px}
  .nav nav a{margin-left:26px;text-decoration:none;color:var(--muted);font-size:14px;letter-spacing:.4px}
  .nav nav a:hover{color:var(--ink)}
  @media(max-width:640px){.nav nav{display:none}}

  /* HERO */
  .hero{position:relative;padding:38px 0 20px;text-align:center}
  .kicker{color:var(--gold);letter-spacing:4px;font-size:12px;text-transform:uppercase;margin:0 0 10px}
  .hero h1{font-size:clamp(34px,6vw,64px);line-height:1.02;margin:0 0 14px;
    background:linear-gradient(180deg,#fff 0%, #d8cfb8 100%);
    -webkit-background-clip:text;background-clip:text;color:transparent}
  .hero p.sub{color:var(--muted);max-width:620px;margin:0 auto 6px;font-size:17px;line-height:1.5}
  .coin-stage{
    position:relative;width:min(560px,86vw);height:min(560px,86vw);margin:6px auto 0;
  }
  #coin-hero{width:100%;height:100%;display:block}
  .stage-glow{
    position:absolute;inset:0;pointer-events:none;
    background:radial-gradient(closest-side, rgba(217,179,74,.10), rgba(217,179,74,0) 70%);
  }
  .cta{display:flex;gap:14px;justify-content:center;flex-wrap:wrap;margin-top:2px}
  .btn{
    border:0;cursor:pointer;font-weight:600;letter-spacing:.5px;
    padding:13px 24px;border-radius:999px;font-size:15px;
  }
  .btn.primary{background:linear-gradient(180deg,var(--gold2),var(--gold) 60%,#a67f24);color:#2a1e05;
    box-shadow:0 6px 22px rgba(217,179,74,.28)}
  .btn.primary:hover{filter:brightness(1.06)}
  .btn.ghost{background:transparent;color:var(--ink);border:1px solid var(--line)}
  .btn.ghost:hover{border-color:rgba(255,255,255,.3)}

  .specs{display:flex;gap:34px;justify-content:center;flex-wrap:wrap;margin:30px 0 6px;color:var(--muted);font-size:13px}
  .specs div b{display:block;color:var(--ink);font-family:Georgia,serif;font-size:22px}

  /* SECTIONS */
  section{padding:74px 0;border-top:1px solid var(--line)}
  .sec-head{text-align:center;max-width:720px;margin:0 auto 44px}
  .sec-head .kicker{margin-bottom:8px}
  .sec-head h2{font-size:clamp(26px,4vw,40px);margin:0 0 14px}
  .sec-head p{color:var(--muted);font-size:16px;line-height:1.6;margin:0}

  .about-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:20px;margin-top:34px}
  @media(max-width:800px){.about-grid{grid-template-columns:1fr}}
  .about-card{background:var(--card);border:1px solid var(--line);border-radius:16px;padding:24px}
  .about-card h3{margin:0 0 8px;font-size:19px}
  .about-card p{margin:0;color:var(--muted);font-size:14px;line-height:1.6}
  .about-card .num{font-family:Georgia,serif;color:var(--gold);font-size:14px;letter-spacing:2px}

  /* EDITIONS */
  .grid{display:grid;grid-template-columns:repeat(4,1fr);gap:22px}
  @media(max-width:900px){.grid{grid-template-columns:repeat(2,1fr)}}
  @media(max-width:520px){.grid{grid-template-columns:1fr}}
  .edition{
    background:linear-gradient(180deg,#181b25,#111319);
    border:1px solid var(--line);border-radius:18px;padding:18px 18px 20px;
    display:flex;flex-direction:column;align-items:center;text-align:center;
    transition:transform .25s ease, border-color .25s ease, box-shadow .25s;
  }
  .edition:hover{transform:translateY(-4px);border-color:rgba(255,255,255,.2);box-shadow:0 18px 40px rgba(0,0,0,.5)}
  .edition-canvas{width:100%;max-width:230px;aspect-ratio:1/1;display:block}
  .edition .name{font-family:Georgia,serif;font-size:21px;margin:8px 0 2px}
  .edition .meta{color:var(--muted);font-size:13px;margin:0 0 4px}
  .edition .price{font-size:15px;letter-spacing:.5px;margin:4px 0 12px;color:var(--ink)}
  .edition[data-state="sold-out"] .price{color:#e0736b}
  .edition[data-state="coming-soon"] .price{color:#7fb0e6}
  .badge{font-size:11px;letter-spacing:2px;text-transform:uppercase;padding:4px 10px;border-radius:999px;margin-bottom:6px}
  .badge.avail{background:rgba(120,200,120,.14);color:#8fe08f;border:1px solid rgba(120,200,120,.3)}
  .badge.sold{background:rgba(224,115,107,.14);color:#e0736b;border:1px solid rgba(224,115,107,.3)}
  .badge.soon{background:rgba(127,176,230,.14);color:#7fb0e6;border:1px solid rgba(127,176,230,.3)}
  .buy{
    border:0;cursor:pointer;width:100%;padding:11px 0;border-radius:10px;font-weight:600;letter-spacing:.4px;font-size:14px;
    background:linear-gradient(180deg,var(--gold2),var(--gold) 60%,#a67f24);color:#2a1e05;
  }
  .buy:hover{filter:brightness(1.06)}
  .locked{width:100%;padding:11px 0;border-radius:10px;font-weight:600;font-size:14px;
    background:rgba(255,255,255,.05);color:var(--muted);border:1px dashed rgba(255,255,255,.15);text-align:center}

  /* PROCESS */
  .steps{display:grid;grid-template-columns:repeat(4,1fr);gap:20px}
  @media(max-width:820px){.steps{grid-template-columns:repeat(2,1fr)}}
  .step{padding:22px;border:1px solid var(--line);border-radius:14px;background:var(--card)}
  .step .n{font-family:Georgia,serif;font-size:30px;color:var(--gold)}
  .step h4{margin:6px 0 6px;font-size:16px}
  .step p{margin:0;color:var(--muted);font-size:13px;line-height:1.55}

  footer{border-top:1px solid var(--line);padding:40px 0;color:var(--muted);font-size:13px;text-align:center}
  footer .brand{justify-content:center;margin-bottom:12px}
  .fine{opacity:.6;margin-top:8px;font-size:12px}
</style>
</head>
<body>

<header class="nav">
  <div class="wrap">
    <div class="brand"><span class="mark"></span><b>WastedToken&nbsp;Mint</b></div>
    <nav>
      <a href="#about">The Mint</a>
      <a href="#editions">Editions</a>
      <a href="#process">Craft</a>
      <a href="#editions">Collect</a>
    </nav>
  </div>
</header>

<main>
  <!-- HERO -->
  <section class="hero" style="border-top:0">
    <div class="wrap">
      <p class="kicker">Struck in metal · Numbered · Forever</p>
      <h1>Challenge coins,<br>minted to outlast us.</h1>
      <p class="sub">WastedToken Mint forges limited-run collectible challenge coins — real weight, reeded edges, deep relief. Every token carries a denomination and a serial. None of it is a JPEG.</p>
    </div>

    <div class="coin-stage">
      <canvas id="coin-hero" width="900" height="900"></canvas>
      <div class="stage-glow"></div>
    </div>

    <div class="wrap">
      <div class="cta">
        <a href="#editions" class="btn primary">Explore the collection</a>
        <a href="#about" class="btn ghost">How they're struck</a>
      </div>
      <div class="specs">
        <div><b>44mm</b>Struck diameter</div>
        <div><b>3.2mm</b>Reeded edge</div>
        <div><b>1.75oz</b>Cast weight</div>
        <div><b>2024</b>Founded</div>
      </div>
    </div>
  </section>

  <!-- ABOUT -->
  <section id="about">
    <div class="wrap">
      <div class="sec-head">
        <p class="kicker">The Mint</p>
        <h2>We waste nothing. We token everything.</h2>
        <p>WastedToken Mint began in a two-press garage workshop with a stubborn idea: that a coin you can hold in your fist beats a thousand you can only screenshot. We design in-house, cut our own dies, and strike every piece under real tonnage. What comes out is heavy, cold, and honest.</p>
      </div>
      <div class="about-grid">
        <div class="about-card">
          <div class="num">01</div>
          <h3>Deep-relief dies</h3>
          <p>Each emblem is hand-sculpted then hard-tooled, so the raised WastedToken crest catches light from across a room — not a flat etch, a real embossed hill of metal.</p>
        </div>
        <div class="about-card">
          <div class="num">02</div>
          <h3>Numbered runs</h3>
          <p>Editions are capped and serialized on the reeded edge. When the run is struck, the die is retired. Sold out means sold out — no repress, no reissue, ever.</p>
        </div>
        <div class="about-card">
          <div class="num">03</div>
          <h3>Redeemable tokens</h3>
          <p>Every coin is stamped with a token denomination. Stack them, trade them, gift them at the bar. They mean whatever your crew decides they mean — and they weigh exactly what a promise should.</p>
        </div>
      </div>
    </div>
  </section>

  <!-- EDITIONS -->
  <section id="editions">
    <div class="wrap">
      <div class="sec-head">
        <p class="kicker">The Collection</p>
        <h2>Four metals. Four moods. One crest.</h2>
        <p>Same die, four finishes, four stories. Two are open, one is gone forever, and one is still cooling in the vault.</p>
      </div>

      <div class="grid">
        <!-- BRONZE -->
        <div class="edition" data-edition="bronze" data-state="available">
          <span class="badge avail">Available</span>
          <canvas class="edition-canvas" width="460" height="460"></canvas>
          <div class="name">Bronze Standard</div>
          <div class="meta">Open edition · 2,000 tokens</div>
          <div class="price">$59</div>
          <button class="buy">Add to cart</button>
        </div>

        <!-- SILVER -->
        <div class="edition" data-edition="silver" data-state="available">
          <span class="badge avail">Available</span>
          <canvas class="edition-canvas" width="460" height="460"></canvas>
          <div class="name">Silver Reserve</div>
          <div class="meta">Ltd. 750 · 5,000 tokens</div>
          <div class="price">$119</div>
          <button class="buy">Add to cart</button>
        </div>

        <!-- GOLD -->
        <div class="edition" data-edition="gold" data-state="sold-out">
          <span class="badge sold">Sold out</span>
          <canvas class="edition-canvas" width="460" height="460"></canvas>
          <div class="name">Gold Founders</div>
          <div class="meta">Ltd. 100 · 10,000 tokens</div>
          <div class="price">SOLD OUT — die retired</div>
          <div class="locked">Vaulted forever</div>
        </div>

        <!-- BLACK / OBSIDIAN -->
        <div class="edition" data-edition="black" data-state="coming-soon">
          <span class="badge soon">Coming soon</span>
          <canvas class="edition-canvas" width="460" height="460"></canvas>
          <div class="name">Obsidian Black</div>
          <div class="meta">Ltd. 250 · 25,000 tokens</div>
          <div class="price">Minting next season — Autumn 2026</div>
          <div class="locked">Notify me · Autumn 2026</div>
        </div>
      </div>
    </div>
  </section>

  <!-- PROCESS -->
  <section id="process">
    <div class="wrap">
      <div class="sec-head">
        <p class="kicker">The Craft</p>
        <h2>From sketch to strike</h2>
        <p>No two mints do it the same. Here's ours, start to shipping box.</p>
      </div>
      <div class="steps">
        <div class="step"><div class="n">1</div><h4>Sculpt</h4><p>The crest is modeled in high relief, every ridge and serif carved for maximum light-catch.</p></div>
        <div class="step"><div class="n">2</div><h4>Tool</h4><p>Dies are cut in hardened tool steel, then reeded so the edge bites the light as it turns.</p></div>
        <div class="step"><div class="n">3</div><h4>Strike</h4><p>Blanks are pressed under full tonnage — a single hit, deep and permanent.</p></div>
        <div class="step"><div class="n">4</div><h4>Number</h4><p>Each coin is serialized on the edge, capsuled, and boxed. Then the die retires.</p></div>
      </div>
    </div>
  </section>
</main>

<footer>
  <div class="wrap">
    <div class="brand"><span class="mark"></span><b>WastedToken&nbsp;Mint</b></div>
    <div>Struck in small batches · Shipped worldwide · Serialized for life</div>
    <div class="fine">© 2026 WastedToken Mint. Tokens are collectibles and carry no monetary value. All coins rendered in-browser, no metals were wasted making this page.</div>
  </div>
</footer>

<script>
"use strict";
/* =========================================================================
   Shared procedural coin renderer (2.5D on 2D canvas).
   A coin = cylinder: two textured faces + reeded edge band.
   Deterministic: render(t) depends only on t.
   ========================================================================= */

// --- vector helpers ---
function norm(v){const l=Math.hypot(v[0],v[1],v[2])||1;return[v[0]/l,v[1]/l,v[2]/l];}
function dot(a,b){return a[0]*b[0]+a[1]*b[1]+a[2]*b[2];}
function cl(x,a,b){return x<a?a:x>b?b:x;}
function c255(x){return x<0?0:x>255?255:x|0;}
const LIGHT = norm([-0.38,0.55,0.92]);   // world light direction
const VIEW  = [0,0,1];
const HALF  = norm([LIGHT[0]+VIEW[0],LIGHT[1]+VIEW[1],LIGHT[2]+VIEW[2]]);

const METALS = {
  hero  :{base:[217,179,74], hi:[255,244,194], lo:[110,78,18],  rim:[74,52,10],  field:[150,116,34]},
  bronze:{base:[192,123,62], hi:[242,196,147],lo:[91,49,19],   rim:[61,36,16],  field:[132,80,40]},
  silver:{base:[205,214,224],hi:[255,255,255],lo:[114,125,140],rim:[74,82,94],  field:[150,160,174]},
  gold  :{base:[224,187,78], hi:[255,246,200],lo:[122,89,26],  rim:[82,60,16],  field:[160,124,40]},
  black :{base:[52,53,64],   hi:[154,160,190],lo:[10,10,16],   rim:[6,6,10],    field:[34,35,46]}
};

const TEX = 460;

/* Build one coin face into an offscreen 2D context.
   isBack: draws denomination; hl: {x,y,a} highlight in texture pixels. */
function buildFace(g, metal, isBack, denom, hl){
  const C=TEX/2, R=TEX/2;
  g.clearRect(0,0,TEX,TEX);
  g.save();
  g.beginPath();g.arc(C,C,R*0.995,0,Math.PI*2);g.clip();

  // base metallic radial field
  const rg=g.createRadialGradient(C*0.78,C*0.66,R*0.05,C,C,R);
  rg.addColorStop(0,`rgb(${metal.hi.join(',')})`);
  rg.addColorStop(0.42,`rgb(${metal.base.join(',')})`);
  rg.addColorStop(0.82,`rgb(${metal.field.join(',')})`);
  rg.addColorStop(1,`rgb(${metal.lo.join(',')})`);
  g.fillStyle=rg;g.beginPath();g.arc(C,C,R,0,Math.PI*2);g.fill();

  // anisotropic brushed sheen
  const lin=g.createLinearGradient(0,0,TEX,TEX);
  lin.addColorStop(0,'rgba(255,255,255,0.10)');
  lin.addColorStop(0.35,'rgba(255,255,255,0)');
  lin.addColorStop(0.6,'rgba(0,0,0,0.10)');
  lin.addColorStop(0.85,'rgba(255,255,255,0.06)');
  lin.addColorStop(1,'rgba(0,0,0,0.12)');
  g.fillStyle=lin;g.beginPath();g.arc(C,C,R,0,Math.PI*2);g.fill();

  const gvert=g.createLinearGradient(0,C-R*0.8,0,C+R*0.8);
  gvert.addColorStop(0,`rgb(${metal.hi.join(',')})`);
  gvert.addColorStop(0.5,`rgb(${metal.base.join(',')})`);
  gvert.addColorStop(1,`rgb(${metal.lo.join(',')})`);
  const engrave=`rgba(${metal.lo[0]},${metal.lo[1]},${metal.lo[2]},0.9)`;

  // recessed inner field ring
  g.save();
  g.strokeStyle=`rgba(0,0,0,0.28)`;g.lineWidth=R*0.02;
  g.beginPath();g.arc(C,C,R*0.9,0,Math.PI*2);g.stroke();
  g.beginPath();g.arc(C,C,R*0.62,0,Math.PI*2);g.stroke();
  g.restore();

  // beaded border
  g.save();
  g.shadowColor='rgba(0,0,0,0.5)';g.shadowBlur=2;g.shadowOffsetX=1;g.shadowOffsetY=1.5;
  g.fillStyle=gvert;
  const beads=54, br=R*0.955;
  for(let i=0;i<beads;i++){const a=i/beads*Math.PI*2;
    g.beginPath();g.arc(C+Math.cos(a)*br,C+Math.sin(a)*br,R*0.014,0,Math.PI*2);g.fill();}
  g.restore();

  // rings (raised)
  g.save();
  g.shadowColor='rgba(0,0,0,0.5)';g.shadowBlur=2;g.shadowOffsetX=1;g.shadowOffsetY=2;
  g.strokeStyle=gvert;g.lineWidth=R*0.02;
  g.beginPath();g.arc(C,C,R*0.86,0,Math.PI*2);g.stroke();
  g.restore();

  // helper: arc text
  function arcText(str,radius,centerAng,arc,size,bottom){
    g.save();
    g.font=`700 ${size}px Georgia, serif`;g.textAlign='center';g.textBaseline='middle';
    g.fillStyle=gvert;
    g.shadowColor='rgba(0,0,0,0.55)';g.shadowBlur=2;g.shadowOffsetX=1;g.shadowOffsetY=2;
    const n=str.length, per=arc/n;
    let start=centerAng-arc/2+per/2;
    for(let i=0;i<n;i++){const a=start+per*i;
      g.save();g.translate(C+Math.cos(a)*radius,C+Math.sin(a)*radius);
      g.rotate(a+(bottom?-Math.PI/2:Math.PI/2));g.fillText(str[i],0,0);g.restore();}
    g.restore();
  }

  // small star helper
  function star(cx,cy,rO,rI,pts,fill){
    g.save();g.beginPath();
    for(let i=0;i<pts*2;i++){const r=i%2?rI:rO;const a=-Math.PI/2+i*Math.PI/pts;
      const x=cx+Math.cos(a)*r,y=cy+Math.sin(a)*r;i?g.lineTo(x,y):g.moveTo(x,y);}
    g.closePath();g.fillStyle=fill;
    g.shadowColor='rgba(0,0,0,0.5)';g.shadowBlur=2;g.shadowOffsetX=1;g.shadowOffsetY=2;
    g.fill();g.restore();
  }

  arcText("WASTED TOKEN MINT", R*0.74, -Math.PI/2, Math.PI*1.05, R*0.088, false);

  if(!isBack){
    arcText("COLLECTIBLE CHALLENGE COIN", R*0.74, Math.PI/2, Math.PI*0.95, R*0.066, true);
    // side stars
    star(C-R*0.74,C,R*0.05,R*0.02,5,gvert);
    star(C+R*0.74,C,R*0.05,R*0.02,5,gvert);
    // central emblem: sunburst + monogram
    star(C,C-R*0.02,R*0.36,R*0.14,12,gvert);
    g.save();
    g.fillStyle=`rgb(${metal.field.join(',')})`;
    g.beginPath();g.arc(C,C-R*0.02,R*0.24,0,Math.PI*2);g.fill();
    g.restore();
    // monogram WT
    g.save();
    g.font=`700 ${R*0.30}px Georgia, serif`;g.textAlign='center';g.textBaseline='middle';
    g.fillStyle=gvert;
    g.shadowColor='rgba(0,0,0,0.6)';g.shadowBlur=3;g.shadowOffsetX=2;g.shadowOffsetY=3;
    g.fillText("W",C-R*0.02,C-R*0.02);
    g.font=`700 ${R*0.14}px Georgia, serif`;
    g.fillStyle=engrave;g.shadowColor='transparent';
    g.fillText("EST · 2024",C,C+R*0.42);
    g.restore();
  } else {
    arcText("★ ONE OUNCE FINE STRIKE ★", R*0.74, Math.PI/2, Math.PI*0.98, R*0.06, true);
    // denomination big
    g.save();
    g.textAlign='center';g.textBaseline='middle';
    g.fillStyle=gvert;
    g.shadowColor='rgba(0,0,0,0.6)';g.shadowBlur=3;g.shadowOffsetX=2;g.shadowOffsetY=3;
    g.font=`800 ${R*0.34}px Georgia, serif`;
    g.fillText(denom, C, C-R*0.12);
    g.font=`700 ${R*0.15}px Georgia, serif`;
    g.fillText("TOKENS", C, C+R*0.16);
    g.shadowColor='transparent';
    g.font=`700 ${R*0.075}px Georgia, serif`;
    g.fillStyle=engrave;
    g.fillText("REDEEMABLE · NON-TRANSFERABLE VALUE", C, C+R*0.44);
    // deco lines
    g.strokeStyle=gvert;g.lineWidth=R*0.012;
    g.beginPath();g.moveTo(C-R*0.34,C+R*0.34);g.lineTo(C+R*0.34,C+R*0.34);g.stroke();
    g.restore();
  }

  // moving specular highlight
  if(hl && hl.a>0.02){
    g.save();
    g.globalCompositeOperation='lighter';
    const hr=R*0.55;
