}

/* =========================================================================
   HERO COIN — animated 3D turn (yaw about vertical + flip about horizontal)
   ========================================================================= */
(function(){
  const canvas=document.getElementById('coin-hero');
  const ctx=canvas.getContext('2d');
  const metal=METALS.hero;
  const H=0.14; // thickness (world units, radius=1)
  const NSEG=170, RIDGES=64;

  // offscreen face textures
  const tcF=document.createElement('canvas');tcF.width=tcF.height=TEX;const gF=tcF.getContext('2d');
  const tcB=document.createElement('canvas');tcB.width=tcB.height=TEX;const gB=tcB.getContext('2d');

  let W=canvas.width, Hh=canvas.height;

  function resize(){
    const cssW=canvas.clientWidth||560;
    const dpr=Math.min(window.devicePixelRatio||1,2);
    const px=Math.round(cssW*dpr);
    if(px>0){canvas.width=px;canvas.height=px;}
    W=canvas.width;Hh=canvas.height;
    render(current);
  }

  function render(t){
    current=t;
    const a=t*Math.PI*2;        // yaw about vertical (y)
    const b=t*Math.PI*2;        // flip about horizontal (x)
    const ca=Math.cos(a),sa=Math.sin(a),cb=Math.cos(b),sb=Math.sin(b);
    // rotation R = Ry(a)*Rx(b); columns:
    const U=[ca,0,-sa];               // local x (right)
    const V=[sa*sb,cb,ca*sb];         // local y (up)
    const N=[sa*cb,-sb,ca*cb];        // local z (face normal)

    const cx=W/2, cy=Hh/2;
    const S=W*0.335;                  // coin radius in px

    // backdrop
    ctx.clearRect(0,0,W,Hh);
    const bg=ctx.createRadialGradient(cx,cy*0.9,S*0.2,cx,cy,W*0.7);
    bg.addColorStop(0,'#1a1f2c');bg.addColorStop(0.5,'#12141d');bg.addColorStop(1,'#0a0b10');
    ctx.fillStyle=bg;ctx.fillRect(0,0,W,Hh);

    // face-plane basis for TEXTURE (right, down):  down = -V so text is upright
    const negV=[-V[0],-V[1],-V[2]];

    // ---- highlight positions (rake across as coin turns) ----
    function hlFor(FR,FD,Nf){
      const spec=Math.pow(Math.max(0,dot(Nf,HALF)),5);
      const ah=cl(dot(LIGHT,FR),-1,1), bh=cl(dot(LIGHT,FD),-1,1);
      return {x:TEX/2*(1+ah*0.85), y:TEX/2*(1+bh*0.85), a:0.30+0.65*spec};
    }
    const frontFR=U, frontFD=negV;
    const backFR=[-U[0],-U[1],-U[2]], backFD=negV;
    buildFace(gF, metal, false, "", hlFor(frontFR,frontFD,N));
    buildFace(gB, metal, true,  "10,000", hlFor(backFR,backFD,[-N[0],-N[1],-N[2]]));

    // ---- draw a face via affine transform of its texture ----
    function drawFace(tex,FR,FD,sign){
      const c=[N[0]*sign*H/2,N[1]*sign*H/2,N[2]*sign*H/2];
      const fx=cx+c[0]*S, fy=cy-c[1]*S;
      const k=2/TEX;
      const m11=k*FR[0]*S, m12=k*(-FR[1])*S;
      const m21=k*FD[0]*S, m22=k*(-FD[1])*S;
      const dx=fx-(m11+m21)*TEX/2, dy=fy-(m12+m22)*TEX/2;
      ctx.save();
      ctx.setTransform(m11,m12,m21,m22,dx,dy);
      ctx.imageSmoothingQuality='high';
      ctx.drawImage(tex,0,0);
      ctx.restore();
      ctx.setTransform(1,0,0,1,0,0);
    }

    // ---- reeded edge band ----
    function drawEdge(){
      const cF=[N[0]*H/2,N[1]*H/2,N[2]*H/2];
      const cB=[-cF[0],-cF[1],-cF[2]];
      for(let i=0;i<NSEG;i++){
        const t0=i/NSEG*Math.PI*2, t1=(i+1)/NSEG*Math.PI*2, tm=(t0+t1)/2;
        // outward normal at mid
        const nx=Math.cos(tm)*U[0]+Math.sin(tm)*V[0];
        const ny=Math.cos(tm)*U[1]+Math.sin(tm)*V[1];
        const nz=Math.cos(tm)*U[2]+Math.sin(tm)*V[2];
        if(nz<=0.02) continue; // back-facing edge hidden
        // corners
        const d0=[Math.cos(t0)*U[0]+Math.sin(t0)*V[0],Math.cos(t0)*U[1]+Math.sin(t0)*V[1]];
        const d1=[Math.cos(t1)*U[0]+Math.sin(t1)*V[0],Math.cos(t1)*U[1]+Math.sin(t1)*V[1]];
        const pFx0=cx+(cF[0]+d0[0])*S, pFy0=cy-(cF[1]+d0[1])*S;
        const pFx1=cx+(cF[0]+d1[0])*S, pFy1=cy-(cF[1]+d1[1])*S;
        const pBx1=cx+(cB[0]+d1[0])*S, pBy1=cy-(cB[1]+d1[1])*S;
        const pBx0=cx+(cB[0]+d0[0])*S, pBy0=cy-(cB[1]+d0[1])*S;
        // lighting
        const diff=Math.max(0,nx*LIGHT[0]+ny*LIGHT[1]+nz*LIGHT[2]);
        // reflect for spec
        const rz=2*nz*(nx*LIGHT[0]+ny*LIGHT[1]+nz*LIGHT[2])-LIGHT[2];
        const spec=Math.pow(Math.max(0,rz),18);
        const ridge=0.62+0.38*(0.5+0.5*Math.sin(i/NSEG*Math.PI*2*RIDGES));
        let lum=(0.22+0.72*diff)*ridge;
        const sp=spec*230;
        const r=c255(metal.base[0]*lum+sp);
        const gr=c255(metal.base[1]*lum+sp);
        const bl=c255(metal.base[2]*lum+sp);
        ctx.fillStyle=`rgb(${r},${gr},${bl})`;
        ctx.beginPath();
        ctx.moveTo(pFx0,pFy0);ctx.lineTo(pFx1,pFy1);
        ctx.lineTo(pBx1,pBy1);ctx.lineTo(pBx0,pBy0);ctx.closePath();ctx.fill();
      }
    }

    // painter order: far face -> edge -> near face
    const frontNear = N[2]>0;
    if(frontNear){
      drawFace(tcB, backFR, backFD, -1);   // back = far
      drawEdge();
      drawFace(tcF, frontFR, frontFD, +1); // front = near
    }else{
      drawFace(tcF, frontFR, frontFD, +1); // front = far
      drawEdge();
      drawFace(tcB, backFR, backFD, -1);   // back = near
    }
  }

  let current=0, raf=null, t0=null;
  const DURATION=9000;
  function loop(ts){
    if(t0===null)t0=ts;
    const t=((ts-t0)%DURATION)/DURATION;
    render(t);
    raf=requestAnimationFrame(loop);
  }
  function play(){ if(raf===null){t0=null;raf=requestAnimationFrame(loop);} }
  function pause(){ if(raf!==null){cancelAnimationFrame(raf);raf=null;} }

  window.addEventListener('resize',resize);
  resize();
  play();

  // Required programmatic API
  window.demo={
    canvas:canvas,
    setTime:function(t){ t=((t%1)+1)%1; render(t); },
    pause:pause,
    play:play
  };
})();

